for i, sd in enumerate(SHELTER_DATA):
    shelter_pets = pets[i*pets_per_shelter : (i+1)*pets_per_shelter]
    shelters.append({
        "id": str(uuid.uuid5(uuid.NAMESPACE_DNS, f"llamaverse.shelter.{sd['name']}")),
        "name": sd["name"],
        "location": sd["location"],
        "specialties": sd["specialties"],
        "description": sd["description"],
        "capacity": 30 + random.randint(0,120),
        "currentResidentCount": len(shelter_pets),
        "availablePetIds": [p["id"] for p in shelter_pets],
    })
    for p in shelter_pets:
        p["shelterId"] = shelters[-1]["id"]
        p["shelterName"] = sd["name"]

