# WRITE EVERYTHING
# ─────────────────────────────────────────────────────────────────────────────
def write_docs(content_type, docs, collections):
    dir_path = os.path.join(BASE, content_type)
    os.makedirs(dir_path, exist_ok=True)
    with open(os.path.join(dir_path, "collections.properties"), "w") as f:
        f.write(f"*={','.join(collections)}\n")
    for doc in docs:
        envelope = {"envelope": {"headers": {"type": content_type}, "instance": {content_type: doc}}}
        with open(os.path.join(dir_path, f"{doc['id']}.json"), "w") as f:
            json.dump(envelope, f, indent=2)
    print(f"  {len(docs)} {content_type} docs -> {dir_path}")

print("Generating llamaverse animal content...")
write_docs("animal-species", SPECIES, ["llamaverse","content","animal-species"])
write_docs("pets", pets, ["llamaverse","content","pets"])
write_docs("animal-shelters", shelters, ["llamaverse","content","animal-shelters"])
print(f"Total: {len(SPECIES)} species, {len(pets)} pets, {len(shelters)} shelters")
print("Done. Run ./gradlew mlLoadData to deploy.")
